/**
 * Modern JavaScript for Foivos Gypas Portfolio (2025)
 * Replaces jQuery dependencies with vanilla JavaScript
 */

class PortfolioApp {
    constructor() {
        this.init();
    }

    init() {
        // Wait for DOM to be fully loaded
        if (document.readyState === 'loading') {
            document.addEventListener('DOMContentLoaded', () => this.setup());
        } else {
            this.setup();
        }
    }

    setup() {
        this.setupNavigation();
        this.setupScrollEffects();
        this.setupMobileMenu();
        this.setupAccessibility();
        this.setupLazyLoading();
        this.updateCopyright();
    }

    setupNavigation() {
        const navLinks = document.querySelectorAll('#nav a[href^="#"]');
        
        navLinks.forEach(link => {
            link.addEventListener('click', (e) => {
                e.preventDefault();
                const targetId = link.getAttribute('href').substring(1);
                const targetElement = document.getElementById(targetId);
                
                if (targetElement) {
                    // Remove active class from all nav links
                    navLinks.forEach(navLink => navLink.classList.remove('active'));
                    
                    // Add active class to clicked link
                    link.classList.add('active');
                    
                    // Smooth scroll to target
                    targetElement.scrollIntoView({
                        behavior: 'smooth',
                        block: 'start'
                    });
                }
            });
        });
    }

    setupScrollEffects() {
        let ticking = false;
        
        const updateActiveNav = () => {
            const sections = document.querySelectorAll('section[id]');
            const navLinks = document.querySelectorAll('#nav a[href^="#"]');
            const scrollPos = window.scrollY + 200;
            
            sections.forEach(section => {
                const sectionTop = section.offsetTop;
                const sectionHeight = section.offsetHeight;
                const sectionId = section.getAttribute('id');
                
                if (scrollPos >= sectionTop && scrollPos < sectionTop + sectionHeight) {
                    navLinks.forEach(link => {
                        link.classList.remove('active');
                        if (link.getAttribute('href') === `#${sectionId}`) {
                            link.classList.add('active');
                        }
                    });
                }
            });
            
            ticking = false;
        };
        
        window.addEventListener('scroll', () => {
            if (!ticking) {
                requestAnimationFrame(updateActiveNav);
                ticking = true;
            }
        });
        
        // Initial call
        updateActiveNav();
    }

    setupMobileMenu() {
        const header = document.getElementById('header');
        const body = document.body;
        
        // Create mobile menu toggle if it doesn't exist
        let toggle = document.getElementById('headerToggle');
        if (!toggle) {
            toggle = document.createElement('div');
            toggle.id = 'headerToggle';
            toggle.innerHTML = '<button class="toggle" aria-label="Toggle navigation menu">☰</button>';
            body.appendChild(toggle);
        }
        
        const toggleButton = toggle.querySelector('.toggle');
        
        toggleButton.addEventListener('click', () => {
            body.classList.toggle('header-visible');
            const isVisible = body.classList.contains('header-visible');
            toggleButton.setAttribute('aria-expanded', isVisible);
        });
        
        // Close menu when clicking outside
        document.addEventListener('click', (e) => {
            if (!header.contains(e.target) && !toggle.contains(e.target)) {
                body.classList.remove('header-visible');
                toggleButton.setAttribute('aria-expanded', 'false');
            }
        });
        
        // Close menu on navigation
        const navLinks = document.querySelectorAll('#nav a');
        navLinks.forEach(link => {
            link.addEventListener('click', () => {
                body.classList.remove('header-visible');
                toggleButton.setAttribute('aria-expanded', 'false');
            });
        });
    }

    setupAccessibility() {
        // Add skip link functionality
        const skipLink = document.querySelector('.skip-link');
        if (skipLink) {
            skipLink.addEventListener('click', (e) => {
                e.preventDefault();
                const target = document.querySelector(skipLink.getAttribute('href'));
                if (target) {
                    target.focus();
                    target.scrollIntoView({ behavior: 'smooth' });
                }
            });
        }

        // Keyboard navigation for nav links
        const navLinks = document.querySelectorAll('#nav a');
        navLinks.forEach((link, index) => {
            link.addEventListener('keydown', (e) => {
                if (e.key === 'ArrowDown' || e.key === 'ArrowRight') {
                    e.preventDefault();
                    const nextIndex = (index + 1) % navLinks.length;
                    navLinks[nextIndex].focus();
                } else if (e.key === 'ArrowUp' || e.key === 'ArrowLeft') {
                    e.preventDefault();
                    const prevIndex = (index - 1 + navLinks.length) % navLinks.length;
                    navLinks[prevIndex].focus();
                }
            });
        });
    }

    setupLazyLoading() {
        // Native lazy loading is supported in modern browsers
        // For older browsers, we can add a polyfill
        if ('loading' in HTMLImageElement.prototype) {
            const images = document.querySelectorAll('img[loading="lazy"]');
            images.forEach(img => {
                img.src = img.src;
            });
        } else {
            // Fallback for older browsers
            const script = document.createElement('script');
            script.src = 'https://polyfill.io/v3/polyfill.min.js?features=IntersectionObserver';
            document.head.appendChild(script);
        }
    }

    updateCopyright() {
        const yearElement = document.getElementById('current-year');
        if (yearElement) {
            yearElement.textContent = new Date().getFullYear();
        }
    }

    // Utility function for smooth scrolling (fallback for older browsers)
    smoothScrollTo(element) {
        const start = window.pageYOffset;
        const target = element.offsetTop - 100; // Offset for fixed header
        const distance = target - start;
        const duration = 800;
        let startTime = null;

        const animation = (currentTime) => {
            if (startTime === null) startTime = currentTime;
            const timeElapsed = currentTime - startTime;
            const run = this.easeInOutQuad(timeElapsed, start, distance, duration);
            window.scrollTo(0, run);
            if (timeElapsed < duration) requestAnimationFrame(animation);
        };

        requestAnimationFrame(animation);
    }

    // Easing function for smooth animation
    easeInOutQuad(t, b, c, d) {
        t /= d / 2;
        if (t < 1) return c / 2 * t * t + b;
        t--;
        return -c / 2 * (t * (t - 2) - 1) + b;
    }
}

// Performance optimizations
class PerformanceOptimizer {
    constructor() {
        this.setupPreloading();
        this.setupCriticalCSS();
    }

    setupPreloading() {
        // Preload critical images
        const criticalImages = [
            '/images/me.jpg'
        ];

        criticalImages.forEach(src => {
            const link = document.createElement('link');
            link.rel = 'preload';
            link.as = 'image';
            link.href = src;
            document.head.appendChild(link);
        });
    }

    setupCriticalCSS() {
        // Add critical CSS loading optimization
        const loadCSS = (href) => {
            const link = document.createElement('link');
            link.rel = 'stylesheet';
            link.href = href;
            link.media = 'print';
            link.onload = function() {
                this.media = 'all';
            };
            document.head.appendChild(link);
        };

        // Load non-critical CSS asynchronously
        if (window.matchMedia('(min-width: 768px)').matches) {
            loadCSS('/assets/css/enhanced.css');
        }
    }
}

// Analytics and tracking (privacy-first)
class Analytics {
    constructor() {
        this.setupPrivacyFriendlyTracking();
    }

    setupPrivacyFriendlyTracking() {
        // Simple, privacy-friendly page view tracking
        // No personal data, no cookies
        const pageData = {
            page: window.location.pathname,
            timestamp: new Date().toISOString(),
            referrer: document.referrer ? new URL(document.referrer).hostname : 'direct',
            userAgent: navigator.userAgent.substring(0, 50)
        };

        // Only track if user hasn't opted out
        if (!localStorage.getItem('analytics-opt-out')) {
            this.trackPageView(pageData);
        }
    }

    trackPageView(data) {
        // Send to your own analytics endpoint (if you have one)
        // This is just a placeholder
        console.log('Page view tracked:', data);
    }
}

// Initialize the application
new PortfolioApp();
new PerformanceOptimizer();
new Analytics();

// Export for testing purposes
if (typeof module !== 'undefined' && module.exports) {
    module.exports = { PortfolioApp, PerformanceOptimizer, Analytics };
}
